// Solution
function validateExposedPorts(dockerComposeFile) {
  const services = dockerComposeFile.split('services:');
  services.shift();
  const exposedPorts = {};
  services.forEach((service) => {
    const serviceName = service.split('  -')[1].split('\n')[0];
    const ports = service.split('\nport: \s+-');
    ports.shift();
    const portArray = ports.map((port) => port.trim());
    if (exposedPorts[serviceName]) {
      exposedPorts[serviceName].push(...portArray);
    } else {
      exposedPorts[serviceName] = [...portArray];
    }
  });
  Object.keys(exposedPorts).forEach((serviceName) => {
    const ports = exposedPorts[serviceName];
    if (ports.some((port) => port < 1024 || port > 65535)) {
      return `Error: ${serviceName} exposes port ${ports[0]}, which is outside the allowed range.`;
    }
  });
  return '';
}

